mapper.select:
SELECT um.USER_ID AS userId, um.MENU_ID AS menuId, m.MENU_NAME AS menuName, m.MENU_URL AS menuUrl, um.AUTH_CODE AS authCode, wt.WORK_GROUP_ID AS workGroupId, wg.GROUP_NAME AS groupName, NVL(wt.TASK_ORDER, 0) AS taskOrder FROM FWK_USER_MENU um JOIN FWK_MENU m ON um.MENU_ID = m.MENU_ID AND m.USE_YN = 'Y' LEFT JOIN FWK_USER_WORK_TASK wt ON um.USER_ID = wt.USER_ID AND um.MENU_ID = wt.MENU_ID LEFT JOIN FWK_USER_WORK_GROUP wg ON wt.USER_ID = wg.USER_ID AND wt.WORK_GROUP_ID = wg.GROUP_ID WHERE um.USER_ID = #{userId}
AND wt.WORK_GROUP_ID = #{workGroupId}
ORDER BY NVL(wt.TASK_ORDER, 0) ASC, um.MENU_ID ASC

mapper.insert:
INSERT INTO FWK_USER_MENU (USER_ID, MENU_ID, AUTH_CODE, LAST_UPDATE_DTIME, LAST_UPDATE_USER_ID, FAVOR_MENU_ORDER) SELECT #{toUserId}, MENU_ID, AUTH_CODE, #{lastUpdateDtime}, #{lastUpdateUserId}, FAVOR_MENU_ORDER FROM FWK_USER_MENU WHERE USER_ID = #{fromUserId} AND MENU_ID IN
#{menuId}
AND NOT EXISTS ( SELECT 1 FROM FWK_USER_MENU WHERE USER_ID = #{toUserId} AND MENU_ID = FWK_USER_MENU.MENU_ID )

